/**
 * AI智能图片编辑器 - 前端核心逻辑
 * 支持7大AI服务商：阿里云、腾讯云、百度AI、智谱AI、OpenAI、Claude、Google、Azure
 */

class AIImageEditor {
    constructor() {
        this.cropper = null;
        this.currentFile = null;
        this.originalImage = null;
        this.selectedProvider = 'aliyun';
        this.selectedFeature = null;
        this.filters = {
            brightness: 100,
            contrast: 100,
            saturate: 100,
            sepia: 0,
            blur: 0
        };
        this.canvas = document.getElementById('previewCanvas');
        this.ctx = this.canvas.getContext('2d');
        this.init();
    }

    init() {
        this.bindEvents();
        this.checkAIProvidersStatus();
    }

    async checkAIProvidersStatus() {
        try {
            const response = await fetch('http://localhost:5000/api/ai/providers');
            const data = await response.json();

            document.querySelectorAll('.provider-btn').forEach(btn => {
                const provider = btn.dataset.provider;
                const statusEl = btn.querySelector('.provider-status');
                if (data.providers && data.providers[provider]) {
                    statusEl.classList.remove('status-offline');
                    statusEl.classList.add('status-online');
                } else {
                    statusEl.classList.remove('status-online');
                    statusEl.classList.add('status-offline');
                }
            });
        } catch (error) {
            console.log('无法连接到AI服务');
        }
    }

    bindEvents() {
        // 上传事件
        const uploadArea = document.getElementById('uploadArea');
        const fileInput = document.getElementById('fileInput');

        uploadArea.addEventListener('click', () => fileInput.click());
        uploadArea.addEventListener('dragover', (e) => {
            e.preventDefault();
            uploadArea.classList.add('dragover');
        });
        uploadArea.addEventListener('dragleave', () => {
            uploadArea.classList.remove('dragover');
        });
        uploadArea.addEventListener('drop', (e) => {
            e.preventDefault();
            uploadArea.classList.remove('dragover');
            const file = e.dataTransfer.files[0];
            if (file && file.type.startsWith('image/')) {
                this.loadImage(file);
            }
        });
        fileInput.addEventListener('change', (e) => {
            const file = e.target.files[0];
            if (file) this.loadImage(file);
        });

        // 选项卡切换
        document.querySelectorAll('.tab').forEach(tab => {
            tab.addEventListener('click', (e) => {
                document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
                document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
                e.target.classList.add('active');
                document.getElementById(`${e.target.dataset.tab}-tab`).classList.add('active');
            });
        });

        // AI服务商选择
        document.querySelectorAll('.provider-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                document.querySelectorAll('.provider-btn').forEach(b => b.classList.remove('active'));
                e.currentTarget.classList.add('active');
                this.selectedProvider = e.currentTarget.dataset.provider;
                console.log('选择AI服务商:', this.selectedProvider);
            });
        });

        // AI功能选择
        document.querySelectorAll('.feature-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                document.querySelectorAll('.feature-btn').forEach(b => b.classList.remove('active'));
                e.currentTarget.classList.add('active');
                this.selectedFeature = e.currentTarget.dataset.feature;
                console.log('选择AI功能:', this.selectedFeature);
            });
        });

        // 基础调整
        ['brightness', 'contrast'].forEach(filter => {
            const slider = document.getElementById(filter);
            slider.addEventListener('input', (e) => {
                this.filters[filter] = parseInt(e.target.value);
                document.getElementById(`${filter}Value`).textContent = `${e.target.value}%`;
